class Playground {
    constructor(slots) {
        this.list = slots.list;
        this.map = slots.map;
    }

    async run(inputs) {
        const capacity = inputs.capacity;
        const actionsStr = inputs.actions;

        this.list.init([]);
        this.map.init([]);
        log('Starting LRU Cache simulation...');
        await awaitStep();

        const parseActions = (str) => {
            const regex = /(\w+)\((\w+)(?:,(\w+))?\)/g;
            const matches = [];
            let match;
            while ((match = regex.exec(str)) !== null) {
                matches.push({ type: match[1], key: match[2], val: match[3] });
            }
            return matches;
        };

        const actions = parseActions(actionsStr);
        const cache = new Map(); // Logical state

        for (const action of actions) {
            if (action.type === 'PUT') {
                log(`PUT ${action.key} = ${action.val}`);
                if (cache.has(action.key)) {
                    log(`Key ${action.key} exists. Updating value and moving to head.`);
                    // Update map
                    cache.set(action.key, action.val);
                    this.map.set(action.key, action.val);
                    this.map.highlight(action.key, '#3b82f6');

                    // Update list (simulated by finding and moving)
                    const idx = this.list.data.findIndex(n => n.val.split(':')[0] === action.key);
                    this.list.highlight(idx, '#ef4444');
                    await awaitStep();

                    this.list.data.splice(idx, 1);
                    this.list.addFirst(`${action.key}:${action.val}`);
                    this.list.highlight(0, '#10b981');
                } else {
                    if (cache.size >= capacity) {
                        log(`Capacity reached. Evicting LRU (Tail)...`);
                        const tailIdx = this.list.data.length - 1;
                        this.list.highlight(tailIdx, '#ef4444');
                        await awaitStep();

                        const lru = this.list.data.pop();
                        const lruKey = lru.val.split(':')[0];
                        cache.delete(lruKey);
                        this.map.delete(lruKey);
                        this.list.render();
                        log(`Evicted ${lruKey}. Adding new key ${action.key}.`);
                        await awaitStep();
                    }

                    log(`Adding ${action.key} to map and head of list.`);
                    cache.set(action.key, action.val);
                    this.map.set(action.key, action.val);
                    this.list.addFirst(`${action.key}:${action.val}`);
                    this.list.highlight(0, '#10b981');
                }
            } else if (action.type === 'GET') {
                log(`GET ${action.key}`);
                if (cache.has(action.key)) {
                    const val = cache.get(action.key);
                    log(`Found ${action.key} = ${val}. Moving to head.`);
                    this.map.highlight(action.key, '#10b981');

                    const idx = this.list.data.findIndex(n => n.val.split(':')[0] === action.key);
                    this.list.highlight(idx, '#ef4444');
                    await awaitStep();

                    this.list.data.splice(idx, 1);
                    this.list.addFirst(`${action.key}:${val}`);
                    this.list.highlight(0, '#10b981');
                } else {
                    log(`Key ${action.key} not found.`);
                    await awaitStep();
                }
            }
            await awaitStep();
            this.map.clearHighlights();
            this.list.clearHighlights();
        }

        log('Simulation complete.');
    }
}
